import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import UptimeBadge from '../components/UptimeBadge';
import SSLBadge from '../components/SSLBadge';

export default function StatusPage() {
  const { slug } = useParams();
  const [data, setData]   = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    axios.get(`/public/${slug}`).then(r => setData(r.data)).catch(() => setError('Status page not found'));
  }, [slug]);

  if (error) return (
    <div className="min-h-screen bg-[#f4f5f7] dark:bg-gh-canvas flex items-center justify-center">
      <div className="text-center">
        <div className="text-6xl font-bold text-gray-200 dark:text-gh-subtle">404</div>
        <h2 className="text-lg font-semibold text-gray-800 dark:text-gh-text mt-2">{error}</h2>
        <p className="text-sm text-gray-500 dark:text-gh-muted mt-1">This status page doesn't exist.</p>
      </div>
    </div>
  );

  if (!data) return (
    <div className="min-h-screen bg-[#f4f5f7] dark:bg-gh-canvas flex items-center justify-center">
      <span className="w-8 h-8 border-4 border-gray-200 dark:border-gh-border border-t-brand-blue dark:border-t-gh-green rounded-full" style={{ animation: 'spin 0.8s linear infinite' }} />
    </div>
  );

  const allUp = data.endpoints.every(e => e.status === 'UP');

  return (
    <div className="min-h-screen bg-[#f4f5f7] dark:bg-gh-canvas">
      <div className="max-w-2xl mx-auto px-4 py-10 space-y-4">
        {/* Header */}
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-gh-text mb-3">{data.teamName}</h1>
          <div className={`inline-flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold border ${
            allUp
              ? 'bg-green-50 text-green-700 border-green-200 dark:bg-transparent dark:text-gh-green-em dark:border-gh-green-em/30'
              : 'bg-red-50 text-red-700 border-red-200 dark:bg-transparent dark:text-red-400 dark:border-red-400/30'
          }`}>
            <span className={`w-2 h-2 rounded-full ${allUp ? 'bg-green-500' : 'bg-red-500'}`} style={{ animation: 'glow-pulse 2s ease-in-out infinite' }} />
            {allUp ? 'All Systems Operational' : 'Degraded Performance'}
          </div>
        </div>

        {/* Services */}
        <div className="bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border overflow-hidden">
          <div className="px-5 py-3 border-b border-gray-100 dark:border-gh-border">
            <span className="text-xs font-semibold uppercase tracking-widest text-gray-400 dark:text-gh-muted">Services</span>
          </div>
          {data.endpoints.map((ep, i) => (
            <div key={ep.id} className={`flex items-center justify-between px-5 py-3.5 ${i > 0 ? 'border-t border-gray-50 dark:border-gh-border' : ''}`}>
              <div className="flex items-center gap-2">
                <span className="text-sm font-medium text-gray-800 dark:text-gh-text">{ep.name}</span>
                <SSLBadge url={ep.url} />
              </div>
              <div className="flex items-center gap-2">
                <span className="text-xs text-gray-500 dark:text-gh-muted bg-gray-100 dark:bg-gh-subtle px-2 py-0.5 rounded-lg">{ep.uptimePercent}% uptime</span>
                <span className="text-xs text-gray-500 dark:text-gh-muted bg-gray-100 dark:bg-gh-subtle px-2 py-0.5 rounded-lg font-mono">{ep.avgLatencyMs}ms</span>
                <UptimeBadge status={ep.status} />
              </div>
            </div>
          ))}
        </div>

        {/* Active Incidents */}
        {data.incidents?.filter(i => !i.resolvedAt).length > 0 && (
          <div className="bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-red-400/20 overflow-hidden">
            <div className="px-5 py-3 border-b border-red-100 dark:border-red-400/20">
              <span className="text-xs font-semibold uppercase tracking-widest text-red-500">⚠ Active Incidents</span>
            </div>
            {data.incidents.filter(i => !i.resolvedAt).map(inc => (
              <div key={inc.id} className="flex items-center gap-2 px-5 py-3 text-sm text-red-600 dark:text-red-400">
                <span className="w-2 h-2 rounded-full bg-red-500 flex-shrink-0" style={{ animation: 'glow-pulse 2s ease-in-out infinite' }} />
                Ongoing since {new Date(inc.startedAt).toLocaleString()}
              </div>
            ))}
          </div>
        )}

        <p className="text-center text-xs text-gray-400 dark:text-gh-dim pt-2">
          Last updated: {new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })}
        </p>
      </div>
    </div>
  );
}
